#include <iostream>

class Counter {
    int m_count{ 0 };
public:
    Counter& add(int n) { m_count += n; return *this; }
    int get() const     { return m_count; }
};

int main() {
    Counter c;
    c.add(3).add(4).add(1);
    std::cout << c.get() << "\n";
}
```

